1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	type QuoteResult = { premium: number };
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  amulet: 60,
21	  sword: 100,
22	  rune: 25,
23	};
24	
25	const FIRST_INSURANCE_RATE = 0.1;
26	const PROCESSING_FEE = 5;
27	
28	const CURSE_SURCHARGE_RATE = 0.5;
29	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const LOYALTY_DISCOUNT_RATE = 0.2;
32	const LOYALTY_THRESHOLD_YEARS = 2;
33	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
34	
35	// Rune-block pricing: 3 runes sold together are priced as a 60 G block
36	// instead of 3 × 25 = 75 G. Adjustment is applied to policy base when an
37	// exact block of 3 runes is present.
38	const RUNE_BLOCK_SIZE = 3;
39	const RUNE_BLOCK_PRICE = 60;
40	const RUNE_BLOCK_ADJUSTMENT =
41	  RUNE_BLOCK_PRICE - RUNE_BLOCK_SIZE * BASE_PREMIUM.rune;
42	
43	function sumOver<T>(xs: T[], f: (x: T) => number): number {
44	  return xs.reduce((total, x) => total + f(x), 0);
45	}
46	
47	// MHPCO rounds quote premiums UP (in the office's favor).
48	function roundUpInFavorOfOffice(amount: number): number {
49	  return Math.ceil(amount);
50	}
51	
52	function itemBasePremium(item: QuoteItem): number {
53	  return BASE_PREMIUM[item.type] ?? 0;
54	}
55	
56	function itemSurcharges(item: QuoteItem): number {
57	  const base = itemBasePremium(item);
58	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
59	  const highEnchantmentSurcharge =
60	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
61	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
62	      : 0;
63	  return curseSurcharge + highEnchantmentSurcharge;
64	}
65	
66	function priceQuoteStep(
67	  step: QuoteStep,
68	  yearsWithMHPCO: number,
69	  isFollowUp: boolean,
70	): QuoteResult {
71	  const runeCount = step.items.filter((x) => x.type === "rune").length;
72	  const runeBlockAdjustment =
73	    runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_ADJUSTMENT : 0;
74	  const policyBase = sumOver(step.items, itemBasePremium) + runeBlockAdjustment;
75	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
76	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
77	  const loyaltyDiscount =
78	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
79	      ? policyBase * LOYALTY_DISCOUNT_RATE
80	      : 0;
81	  const followUpDiscount = isFollowUp
82	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
83	    : 0;
84	  const premium = roundUpInFavorOfOffice(
85	    policyBase +
86	      itemSurchargeTotal +
87	      firstInsurance -
88	      loyaltyDiscount -
89	      followUpDiscount +
90	      PROCESSING_FEE,
91	  );
92	  return { premium };
93	}
94	
95	export function runScenario(scenario: Scenario): {
96	  results: QuoteResult[];
97	} {
98	  const results = scenario.steps.map((step, index) =>
99	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0),
100	  );
101	  return { results };
102	}
